// Alvea :: valutazione soglie + scrittura InfluxDB (line protocol)
const r = msg.payload;
if (!r || !r.device_id) { node.warn("payload non valido"); return [null, null]; }

const INFLUX_URL = env.get("INFLUX_URL") || "http://influxdb:8086";
const ORG    = env.get("INFLUX_ORG")    || "alvea";
const BUCKET = env.get("INFLUX_BUCKET") || "vitals";
const TOKEN  = env.get("INFLUX_TOKEN")  || "alvea-admin-token";

// Soglie cliniche (didattiche), coerenti con la documentazione
const BPM_WARN_LOW=100, BPM_WARN_HIGH=140, BPM_CRIT_LOW=80, BPM_CRIT_HIGH=170;
const T_WARN_LOW=36.0, T_WARN_HIGH=37.2, T_CRIT_LOW=35.0, T_CRIT_HIGH=38.5;
const CONTACT_DEBOUNCE = 5; // secondi consecutivi senza contatto

const contact = r.sensor_contact;
let alerts = [];

if (!contact) {
    // Regola d'oro: fascia staccata -> niente allarmi fisiologici, solo tecnico
    let lost = (context.get('lost') || 0) + 1;
    context.set('lost', lost);
    if (lost === CONTACT_DEBOUNCE) {
        alerts.push({kind:'contact_lost', severity:'technical',
                     message:'Fascia non a contatto: rilevazione sospesa'});
    }
} else {
    context.set('lost', 0);
    const bpm = r.bpm, t = r.temperature;
    if (bpm > 0) {
        if (bpm <= BPM_CRIT_LOW)       alerts.push({kind:'bpm_low', severity:'critical', message:'Bradicardia critica: '+bpm+' BPM'});
        else if (bpm >= BPM_CRIT_HIGH) alerts.push({kind:'bpm_high',severity:'critical', message:'Tachicardia critica: '+bpm+' BPM'});
        else if (bpm <  BPM_WARN_LOW)  alerts.push({kind:'bpm_low', severity:'warning',  message:'BPM sotto soglia: '+bpm});
        else if (bpm >  BPM_WARN_HIGH) alerts.push({kind:'bpm_high',severity:'warning',  message:'BPM sopra soglia: '+bpm});
    }
    if (t > 0) {
        if (t <= T_CRIT_LOW)       alerts.push({kind:'temp_low', severity:'critical', message:'Ipotermia critica: '+t+' C'});
        else if (t >= T_CRIT_HIGH) alerts.push({kind:'temp_high',severity:'critical', message:'Febbre alta: '+t+' C'});
        else if (t <  T_WARN_LOW)  alerts.push({kind:'temp_low', severity:'warning',  message:'Temperatura bassa: '+t+' C'});
        else if (t >  T_WARN_HIGH) alerts.push({kind:'temp_high',severity:'warning',  message:'Temperatura alta: '+t+' C'});
    }
}

// --- Line protocol InfluxDB v2 (measurement = vitals) ---
const contactInt = contact ? 1 : 0;
const tags   = "device_id=" + r.device_id + ",source=" + (r.source || "unknown");
const fields = "bpm=" + r.bpm + ",temperature=" + r.temperature +
               ",sensor_contact=" + contactInt + "i,alert_count=" + alerts.length + "i";
const line = "vitals," + tags + " " + fields;

const influxMsg = {
    method: "POST",
    url: INFLUX_URL + "/api/v2/write?org=" + ORG + "&bucket=" + BUCKET + "&precision=s",
    headers: {
        "Authorization": "Token " + TOKEN,
        "Content-Type": "text/plain; charset=utf-8"
    },
    payload: line
};

let alertMsg = null;
if (alerts.length > 0) {
    node.status({fill:"red", shape:"dot", text:alerts[0].severity+": "+alerts[0].kind});
    alertMsg = {
        topic: "alvea/alerts",
        payload: JSON.stringify({device_id:r.device_id, ts:Date.now(), alerts:alerts})
    };
} else {
    node.status({fill:"green", shape:"dot", text:"ok"});
}

return [influxMsg, alertMsg];
